import{_ as n,c as s,o as a,a as t}from"./app.71f27b91.js";const e='{"title":"Global Properties","description":"","frontmatter":{},"headers":[{"level":2,"title":"app.config.globalProperties","slug":"app-config-globalproperties"},{"level":2,"title":"Application-level provide / inject","slug":"application-level-provide-inject"},{"level":2,"title":"ES modules","slug":"es-modules"},{"level":2,"title":"Sharing state using Vuex or Pinia","slug":"sharing-state-using-vuex-or-pinia"},{"level":2,"title":"Global mixins","slug":"global-mixins"},{"level":2,"title":"Using components instead of properties","slug":"using-components-instead-of-properties"},{"level":2,"title":"Patching third-party libraries","slug":"patching-third-party-libraries"}],"relativePath":"patterns/global-properties.md","lastUpdated":1649708836587}',p={},o=[t('<h1 id="global-properties" tabindex="-1">Global Properties <a class="header-anchor" href="#global-properties" aria-hidden="true">#</a></h1><p>TLDR: You probably want <a href="#es-modules">ES modules</a> instead.</p><p>In Vue 2 it was possible to create &#39;global properties&#39; by doing something like:</p><div class="language-js"><pre><code><span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>$http <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>This would then be available in all components by accessing <code>this.$http</code>.</p><p>In Vue 3 there isn&#39;t a <code>Vue.prototype</code>, but there are various alternatives to solve the same problems. Whether it&#39;s appropriate to describe them as &#39;global&#39;, or even as &#39;properties&#39;, is questionable in some cases, but the desired outcome remains the same.</p><h2 id="app-config-globalproperties" tabindex="-1"><code>app.config.globalProperties</code> <a class="header-anchor" href="#app-config-globalproperties" aria-hidden="true">#</a></h2><p>The most direct replacement in Vue 3 is called <code>globalProperties</code>:</p><div class="language-js"><pre><code><span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n\napp<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$http <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>This allows us to use <code>this.$http</code>, just like in Vue 2.</p><p>You&#39;ll find this approach used in some official Vue libraries. For example, Vuex exposes <code>$store</code> and Vue Router exposes <code>$router</code> and <code>$route</code>. The mapping helpers provided by Vuex, e.g. <code>mapState</code>, all rely on using <code>this.$store</code> to access the correct store. These helpers wouldn&#39;t be possible using most of the other techniques described on this page.</p><p>However, the use of <code>globalProperties</code> in those official libraries shouldn&#39;t be seen as an endorsement to use them everywhere. Those libraries have some specific requirements that typically don&#39;t apply to application code.</p><p>There are a few problems with using <code>globalProperties</code>, including:</p><ol><li>There&#39;s no <code>this</code> inside <code>setup</code>.</li><li>The properties exist in components without any explicit definition.</li></ol><p>The <code>$</code> prefix tends to be well understood as meaning &#39;magically injected from outside&#39;, but, if the name doesn&#39;t give a clear indication of where exactly it came from, it can cause confusion, especially for new developers. However, if this technique is used sparingly, and only for properties that are used often, it is unlikely to cause any serious impediment to understanding.</p><p>What one person describes as &#39;more explicit&#39;, another might call &#39;verbose&#39; or &#39;unnecessary boilerplate&#39;. Such terms can be used to express a subjective view of a technique, but they aren&#39;t an objective proof of the superiority of one approach over another.</p><p>In particular, these global properties can be useful to expose helper functions to the template. For example, <code>globalProperties</code> might be used to share formatting functions:</p><div class="language-js"><pre><code>app<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$format <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token function">currencyUSD</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token string">&#39;$&#39;</span> <span class="token operator">+</span> value<span class="token punctuation">.</span><span class="token function">toFixed</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span><span class="token punctuation">&gt;</span></span>{{ $format.currencyUSD(item.unitPrice) }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>This would be one way to replace <em>filters</em>, which no longer exist in Vue 3.</p><p>Other use cases for <code>globalProperties</code> in templates might be viewport breakpoints or permissions checks:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name">v-if</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>$viewport.isNarrow<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>admin-menu</span> <span class="token attr-name">v-if</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>$permissions.has(<span class="token punctuation">&#39;</span>admin<span class="token punctuation">&#39;</span>)<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>user-menu</span> <span class="token attr-name">v-else</span> <span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>An alternative in this case would be to use a component instead, which we&#39;ll discuss <a href="#using-components-instead-of-properties">later</a>.</p><p><code>globalProperties</code> work nicely for things you only need in the template, or if you&#39;re using the Options API.</p><p>But the lack of availability in <code>setup</code> is a major problem, so let&#39;s consider some other alternatives to <code>globalProperties</code>.</p><h2 id="application-level-provide-inject" tabindex="-1">Application-level <code>provide</code> / <code>inject</code> <a class="header-anchor" href="#application-level-provide-inject" aria-hidden="true">#</a></h2><p>The standard solution for use with the Composition API is to use <code>provide</code> on the application and <code>inject</code> in <code>setup</code>. The latter will usually be wrapped in a dedicated helper function. We see this approach with Vuex and Vue Router, which have functions such as <code>useStore</code> and <code>useRouter</code> implemented this way.</p><p>Continuing the earlier example for <code>axios</code>:</p><div class="language-js"><pre><code><span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> http <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n\napp<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$http <span class="token operator">=</span> http\napp<span class="token punctuation">.</span><span class="token function">provide</span><span class="token punctuation">(</span><span class="token string">&#39;http&#39;</span><span class="token punctuation">,</span> http<span class="token punctuation">)</span>\n</code></pre></div><p>While we could use <code>inject(&#39;http&#39;)</code> directly in each component, it&#39;d be better to create a wrapper that hides the implementation details behind an abstraction:</p><div class="language-js"><pre><code><span class="token keyword">const</span> <span class="token function-variable function">useHttp</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token function">inject</span><span class="token punctuation">(</span><span class="token string">&#39;http&#39;</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>In practice, this would often use a <code>Symbol</code> instead of a string key, ensuring no naming collisions can occur. This would then be wrapped up in a plugin. A more realistic example might look something like this:</p><div class="language-js"><pre><code><span class="token comment">// main.js</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> createApp <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> plugin <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./axiosPlugin.js&#39;</span>\n\n<span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span><span class="token punctuation">}</span><span class="token punctuation">)</span>\napp<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>plugin<span class="token punctuation">)</span>\n</code></pre></div><div class="language-js"><pre><code><span class="token comment">// axiosPlugin.js</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> inject <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> axios <span class="token keyword">from</span> <span class="token string">&#39;axios&#39;</span>\n\n<span class="token keyword">const</span> injectionKey <span class="token operator">=</span> <span class="token function">Symbol</span><span class="token punctuation">(</span><span class="token string">&#39;http&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">export</span> <span class="token keyword">const</span> <span class="token function-variable function">useHttp</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">inject</span><span class="token punctuation">(</span>injectionKey<span class="token punctuation">)</span>\n\n<span class="token keyword">export</span> <span class="token keyword">const</span> plugin <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token function">install</span> <span class="token punctuation">(</span><span class="token parameter">app</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">const</span> http <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n    app<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$http <span class="token operator">=</span> http\n    app<span class="token punctuation">.</span><span class="token function">provide</span><span class="token punctuation">(</span>injectionKey<span class="token punctuation">,</span> http<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> useHttp <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./axiosPlugin.js&#39;</span>\n\n<span class="token keyword">const</span> http <span class="token operator">=</span> <span class="token function">useHttp</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><h2 id="es-modules" tabindex="-1">ES modules <a class="header-anchor" href="#es-modules" aria-hidden="true">#</a></h2><p>While the techniques above can be very useful, in many cases there&#39;s no need to reach for a Vue-specific solution at all. ES modules are often more than adequate for sharing &#39;global&#39; values.</p><p>Taking the <code>axios</code> example, we could just export the instance from a module:</p><div class="language-js"><pre><code><span class="token comment">// http.js</span>\n<span class="token keyword">export</span> <span class="token keyword">default</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>That can then be imported wherever we need it:</p><div class="language-js"><pre><code><span class="token keyword">import</span> http <span class="token keyword">from</span> <span class="token string">&#39;./http.js&#39;</span>\n</code></pre></div><p>This flips the dependency. Rather than having a value injected from outside, the dependency is an explicit import from a specific location. The gain in explicitness comes with a small loss in the reusability of the component.</p><p>ES modules also work well outside of Vue components. For the <code>axios</code> example, it&#39;s common to need the same <code>axios</code> instance in Vuex actions. While there are other ways that can be achieved, using an ES module is the most widely used in real applications.</p><h2 id="sharing-state-using-vuex-or-pinia" tabindex="-1">Sharing state using Vuex or Pinia <a class="header-anchor" href="#sharing-state-using-vuex-or-pinia" aria-hidden="true">#</a></h2><p>It can also be useful to share state globally. We could just use ES modules and Vue&#39;s Reactivity APIs to implement shared state ourselves:</p><div class="language-js"><pre><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>Then anything that needs this state object can use <code>import</code> to pull it in.</p><p>However, this roll-your-own approach tends to lead to problems. Standard solutions, such as <a href="https://next.vuex.vuejs.org/" target="_blank" rel="noopener noreferrer">Vuex</a> or <a href="https://pinia.esm.dev/" target="_blank" rel="noopener noreferrer">Pinia</a>, provide several benefits:</p><ul><li>Documented APIs.</li><li>Familiarity among developers.</li><li>Standard usage patterns that, by design, avoid common problems.</li><li>Integration with Vue Devtools.</li><li>You don&#39;t have to maintain the code yourself.</li></ul><p>So if you need a reactive, central store for your state, you should probably be using either Vuex or Pinia.</p><h2 id="global-mixins" tabindex="-1">Global mixins <a class="header-anchor" href="#global-mixins" aria-hidden="true">#</a></h2><p>This is rarely the right approach, but it is worth being aware that global mixins can be used as an alternative to <code>globalProperties</code>. For example:</p><div class="language-js"><pre><code><span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n\napp<span class="token punctuation">.</span><span class="token function">mixin</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  computed<span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token function">$value</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token comment">// We have access to `this` if we need it.</span>\n      <span class="token comment">// Using `computed` makes this reactive.</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>Global mixins add extra overhead to the creation of every component in your application, which usually makes them unsuitable for anything other than debugging trickery used during development.</p><h2 id="using-components-instead-of-properties" tabindex="-1">Using components instead of properties <a class="header-anchor" href="#using-components-instead-of-properties" aria-hidden="true">#</a></h2><p>Earlier we saw how <code>globalProperties</code> could be used for exposing things like viewport breakpoints of permissions to the template.</p><p>An alternative approach would be to implement these features using components. These would be <em>renderless components</em>, just rendering the contents of their slots if the relevant criteria are met. e.g.:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>permission-check</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>admin<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>admin-menu</span> <span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>permission-check</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>If you want the equivalent of <code>v-if</code>/<code>v-else</code> you can use two slots:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>permission-check</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>admin<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name">#allowed</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>admin-menu</span> <span class="token punctuation">/&gt;</span></span>  \n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name">#denied</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>user-menu</span> <span class="token punctuation">/&gt;</span></span>    \n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>  \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>permission-check</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>The <code>permission-check</code> component would still need some way of accessing the &#39;global&#39; data, and for that it would use one of the other techniques described on this page. The key thing about this approach is that only this one component would need to worry about how the global data is passed around, everything else would just use the component. If you need to refactor how the data is passed around it will only impact this one component.</p><p>To give a concrete example of how <code>permission-check</code> might be implemented in conjunction with Vuex:</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useStore <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vuex&#39;</span>\n\n<span class="token comment">// Using a functional component, so this is effectively just a render function.</span>\n<span class="token comment">// It doesn&#39;t render any VNodes of its own, just those created by its slots.</span>\n<span class="token keyword">const</span> <span class="token function-variable function">PermissionCheck</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter"><span class="token punctuation">{</span> name <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> slots <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token keyword">const</span> hasPermission <span class="token operator">=</span> <span class="token function">useStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>state<span class="token punctuation">.</span>permissions<span class="token punctuation">[</span>name<span class="token punctuation">]</span>\n  \n  <span class="token keyword">if</span> <span class="token punctuation">(</span>hasPermission<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> slots<span class="token punctuation">.</span>allowed<span class="token operator">?.</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">||</span> slots<span class="token punctuation">.</span>default<span class="token operator">?.</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  \n  <span class="token keyword">return</span> slots<span class="token punctuation">.</span>denied<span class="token operator">?.</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>Using a functional component isn&#39;t strictly necessary, but they are well suited to creating renderless components like these.</p><h2 id="patching-third-party-libraries" tabindex="-1">Patching third-party libraries <a class="header-anchor" href="#patching-third-party-libraries" aria-hidden="true">#</a></h2><p>Some third-party libraries, especially those ported from Vue 2, add values to <code>globalProperties</code> via a plugin, but don&#39;t <code>provide</code> the value for compatibility with <code>setup</code>.</p><p>This is usually relatively easy to patch.</p><p>Let&#39;s assume we have a third-party plugin like this:</p><div class="language-js"><pre><code><span class="token comment">// axiosPlugin.js</span>\n<span class="token keyword">import</span> axios <span class="token keyword">from</span> <span class="token string">&#39;axios&#39;</span>\n\n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n  <span class="token function">install</span> <span class="token punctuation">(</span><span class="token parameter">app</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    app<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$http <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>We can add the <code>provide</code> call ourselves from within <code>main.js</code>, after the plugin creates the property:</p><div class="language-js"><pre><code><span class="token comment">// main.js</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> createApp <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> axiosPlugin <span class="token keyword">from</span> <span class="token string">&#39;./axiosPlugins.js&#39;</span>\n\n<span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\napp<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>axiosPlugin<span class="token punctuation">)</span>\napp<span class="token punctuation">.</span><span class="token function">provide</span><span class="token punctuation">(</span><span class="token string">&#39;http&#39;</span><span class="token punctuation">,</span> app<span class="token punctuation">.</span>config<span class="token punctuation">.</span>globalProperties<span class="token punctuation">.</span>$http<span class="token punctuation">)</span>\n</code></pre></div>',71)];var c=n(p,[["render",function(n,t,e,p,c,i){return a(),s("div",null,o)}]]);export{e as __pageData,c as default};
